<?php
use Admin_Model_PageEshop as PageEshop;
use common\logic\Eshop\Eshop;
use Common_Model_Eshop as ModelEshop;

/**
 * Admin_Model_Page
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 * 
 * @package    ##PACKAGE##
 * @subpackage ##SUBPACKAGE##
 * @author     ##NAME## <##EMAIL##>
