 */
class Admin_Model_Page extends Admin_Model_Base_Page {

    const ID_HOMEPAGE = 1;
    const ID_REGISTER = 11;

    /**
     * @param Doctrine_Connection|null $conn
     */
    public function save(Doctrine_Connection $conn = null) {
        $isNew = $this->ID == null;

        parent::save($conn);

        if ( $isNew ) {
            foreach (ModelEshop::getEshops() as $eshop) {
                $pageEshop = new PageEshop();
                $pageEshop->Eshop_ID = $eshop->ID;
                $pageEshop->Page_ID = $this->ID;
                $pageEshop->Active = true;
                $pageEshop->save();
            }
        }
    }

    /**
     * @param int $ID
     * @param Eshop|null $eshop
     * @return array|null
     */
    public static function getPageByID(int $ID, Eshop $eshop = null): ?array {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->select('object.*, pageLangs.Name as Name, pageLangs.Content as Content, pageLangs.Title as Title, pageLangs.MetaDescription as MetaDescription, pageLangs.MetaKeywords as MetaKeywords');
        $query->from('Admin_Model_Page object');
        $query->where('object.ID = ?', $ID);
        $query->leftJoin('object.pageLangs pageLangs With pageLangs.Language_ID = ?', $eshop->Language_ID);
        $page = $query->execute()->toArray();

        return $page ? $page[0] : null;
    }

    /**
     * @param string $slug
     * @param Eshop|null $eshop
     * @return array|null
     */
    public static function getPageBySlug(string $slug, Eshop $eshop = null): ?array {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->select('object.*, pageLangs.Name as Name, pageLangs.Content as Content, pageLangs.Title as Title, pageLangs.MetaDescription as MetaDescription, pageLangs.MetaKeywords as MetaKeywords, , pageLangs.slug as slug');
        $query->from('Admin_Model_Page object');
        $query->leftJoin('object.pageLangs pageLangs With pageLangs.Language_ID = ?', $eshop->Language_ID);
        $query->where('pageLangs.slug = ?', $slug);
        $page = $query->execute()->toArray();

        return $page ? $page[0] : null;
    }

    /**
     * Vrací produkty pro sitemapy
     * @param Common_Model_Eshop|null $eshop
     * @return array|Doctrine_Collection
     */
    public static function loadPagesSitemap(?ModelEshop $eshop = null): array|Doctrine_Collection {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Page object');
        $query->select('object.ID, pageLangs.slug as slug');
        $query->innerJoin('object.pageEshops pageEshops WITH pageEshops.Eshop_ID = ? AND pageEshops.Active = ?', [$eshop->ID, true]);
        $query->innerJoin('object.pageLangs pageLangs WITH pageLangs.Language_ID = ?', [$eshop->Language_ID]);
        $query->andWhere('object.ID != ?', self::ID_HOMEPAGE);

        return $query->execute([], Doctrine_Core::HYDRATE_ARRAY);
    }
}